import React, { useLayoutEffect, useState } from "react";
import { Table } from "semantic-ui-react";
import { useSparePartsTableHooks } from "./spare-parts-stock-table-hooks";

const SparePartsStockTable = () => {
  const spareParts = useSparePartsTableHooks();
  return (
    <div title="Spare Parts Stock Table">
      <Table>
        <Table.Header>
          <Table.Row>
            <Table.HeaderCell>ID</Table.HeaderCell>
            <Table.HeaderCell>Code</Table.HeaderCell>
            <Table.HeaderCell>Description</Table.HeaderCell>
            <Table.HeaderCell>Brand</Table.HeaderCell>
            <Table.HeaderCell>Model</Table.HeaderCell>
            <Table.HeaderCell>Hospital</Table.HeaderCell>
            <Table.HeaderCell>Quantity at Stock</Table.HeaderCell>
            <Table.HeaderCell>Required Quantity</Table.HeaderCell>
          </Table.Row>
        </Table.Header>
        <Table.Body>
          {spareParts.map((part) => (
            <Table.Row key={part.id}>
              <Table.Cell>{part.id}</Table.Cell>
              <Table.Cell>{part.code}</Table.Cell>
              <Table.Cell>{part.description}</Table.Cell>
              <Table.Cell>{part.brand}</Table.Cell>
              <Table.Cell>{part.model}</Table.Cell>
              <Table.Cell>{part.hospital}</Table.Cell>
              <Table.Cell>{part.currentQuantity}</Table.Cell>
              <Table.Cell>{part.requiredQuantity}</Table.Cell>
            </Table.Row>
          ))}
        </Table.Body>
      </Table>
    </div>
  );
};

export default SparePartsStockTable;
